    "Founder & clinical lead": { he:"מייסד ומוביל קליני", ar:"المؤسس والمسؤول السريري", ru:"Основатель и клинический руководитель", es:"Fundador y director clínico", fr:"Fondateur et responsable clinique", de:"Gründer & klinische Leitung" },
    "Founder · Integrative Nutrition & Wellness": { he:"מייסד · תזונה ובריאות אינטגרטיבית", ar:"مؤسس · التغذية والعافية التكاملية", ru:"Основатель · интегративное питание и благополучие", es:"Fundador · Nutrición y bienestar integrativos", fr:"Fondateur · Nutrition et bien-être intégratifs", de:"Gründer · Integrative Ernährung & Wellness" },
