    "Multi-practitioner teams and care groups.": { he:"צוותים רב-מטפליים וקבוצות טיפול.", ar:"فرق متعددة الممارسين ومجموعات رعاية.", ru:"Команды специалистов и группы ухода.", es:"Equipos multiprofesionales y grupos de cuidado.", fr:"Équipes pluri-praticiens et groupes de soin.", de:"Teams mehrerer Fachkräfte und Pflegegruppen." },
    "Contact sales": { he:"ליצירת קשר עם המכירות", ar:"تواصل مع المبيعات", ru:"Связаться с отделом продаж", es:"Contactar ventas", fr:"Contacter les ventes", de:"Vertrieb kontaktieren" },
    "Unlimited clients": { he:"לקוחות ללא הגבלה", ar:"عملاء بلا حدود", ru:"Безлимит клиентов", es:"Clientes ilimitados", fr:"Clients illimités", de:"Unbegrenzte Klienten" },
    "Team roles + audit": { he:"תפקידי צוות + ביקורת", ar:"أدوار الفريق + تدقيق", ru:"Роли команды + аудит", es:"Roles de equipo + auditoría", fr:"Rôles d'équipe + audit", de:"Teamrollen + Audit" },
    "HIPAA-ready": { he:"מוכן ל-HIPAA", ar:"متوافق مع HIPAA", ru:"Готовность к HIPAA", es:"Preparado para HIPAA", fr:"Compatible HIPAA", de:"HIPAA-bereit" },
