    "Press": { he:"עיתונות", ar:"الصحافة", ru:"Пресса", es:"Prensa", fr:"Presse", de:"Presse" },
    "Journal": { he:"בלוג", ar:"المدوّنة", ru:"Журнал", es:"Revista", fr:"Journal", de:"Journal" },
    "Help center": { he:"מרכז עזרה", ar:"مركز المساعدة", ru:"Центр помощи", es:"Centro de ayuda", fr:"Centre d'aide", de:"Hilfe-Center" },
    "For practitioners": { he:"למטפלים", ar:"للممارسين", ru:"Для специалистов", es:"Para profesionales", fr:"Pour les praticiens", de:"Für Fachkräfte" },
    "Privacy": { he:"פרטיות", ar:"الخصوصية", ru:"Конфиденциальность", es:"Privacidad", fr:"Confidentialité", de:"Datenschutz" },
